42	function countRecentTasks(name: string, events: StateEvent[], days: number): number {
43	  const cutoff = new Date();
44	  cutoff.setDate(cutoff.getDate() - days);
45	  const cutoffStr = cutoff.toISOString();
46	  return events.filter(
47	    (e) => e.type === "specialist_spawn" && e.ts >= cutoffStr &&
48	      ((e.payload.name as string) === name || (e.payload.target as string) === name)
49	  ).length;
50	}
