227	      const name = safeDecode(spHistoryMatch[1]);
228	      if (name === null) { json(res, { error: "bad name" }, 400); return; }
229	      const events = getRecentEvents(2000);
230	      const spawns = new Map<string, StateEvent>();
231	      const history: Array<Record<string, unknown>> = [];
232	      for (const e of events) {
233	        if (e.type === "specialist_spawn" &&
234	            ((e.payload.name as string) === name || (e.payload.target as string) === name)) {
