241	          const spawn = spawns.get(taskId);
242	          const startTime = spawn?.ts ?? e.ts;
243	          const endTime = e.ts;
244	          const elapsed = Math.round((new Date(endTime).getTime() - new Date(startTime).getTime()) / 1000);
245	          history.push({
246	            taskId,
247	            goal: (e.payload.goal as string) ?? (spawn?.payload.goal as string) ?? "",
248	            status: (e.payload.status as string) ?? (e.payload.error ? "failed" : "done"),
249	            startTime, endTime, elapsedSec: elapsed,
250	            turns: e.payload.turns, verifier: e.payload.verifier,
251	          });
252	        }
253	      }
254	      json(res, history.reverse().slice(0, 20));
255	      return;
256	    }
