258	    const spArtifactsMatch = p.match(/^\/api\/specialists\/([^/]+)\/artifacts$/);
259	    if (spArtifactsMatch && req.method === "GET") {
260	      const name = safeDecode(spArtifactsMatch[1]);
261	      if (name === null) { json(res, { error: "bad name" }, 400); return; }
262	      const artifactsDir = path.join(config.memoryDir, "artifacts");
263	      try {
264	        const files = await readdir(artifactsDir);
265	        // 檔名格式 <date>_<taskId>_<specialist>_<slug>.json；taskId 本身可含底線
266	        // （如 pt_codegen_probe），positional split 會解錯，用 specialist name 錨定。
267	        const nameRe = new RegExp(`^(\\d{4}-\\d{2}-\\d{2})_(.+?)_${escapeRegex(name)}_(.+)\\.json$`);
268	        const matched = files.filter((f) => nameRe.test(f)).sort().reverse().slice(0, 20);
269	        const entries = await Promise.all(matched.map(async (f) => {
270	          const m = f.match(nameRe)!;
