149	/** Send a message to another bot via configured transport + mirror to group. */
150	export async function sendRelay(targetBot: string, text: string): Promise<void> {
151	  if (!cfg || !bot) return;
152	  if (process.env.RELAY_PAUSED === "true") {
153	    console.log(`[relay] RELAY_PAUSED — blocked outgoing to "${targetBot}"`);
154	    return;
155	  }
156	  // Guard: never relay to self (agent confused the target).
157	  if (targetBot === cfg.botName) {
158	    console.warn(`[relay] blocked self-send (target="${targetBot}"), text: ${text.slice(0, 80)}`);
159	    return;
160	  }
161	  // Guard: skip empty or placeholder-only messages (e.g. "...", "…").
162	  const trimmed = text.replace(/[.\s…]+/g, "");
163	  if (!trimmed) {
164	    console.warn(`[relay] blocked empty/placeholder relay to "${targetBot}": "${text.slice(0, 40)}"`);
165	    return;
166	  }
167	
168	  const transport = cfg.transport;
169	  let sent = false;
170	
171	  // Telegram bot-to-bot transport
172	  if (transport === "telegram" || transport === "both") {
173	    const target = cfg.targetBotUsername;
174	    if (target) {
175	      try {
176	        const payload = `[RELAY:${cfg.botName}] ${text}`;
177	        await bot.api.sendMessage(target, payload);
178	        sent = true;
179	        console.log(`[relay] ✓ sent via TELEGRAM to ${target} (transport=${transport})`);
180	      } catch (err) {
181	        console.error(`[relay] telegram sendMessage to ${target} failed:`, err);
182	        if (transport === "both") console.log(`[relay] falling back to REDIS...`);
183	      }
184	    }
185	  }
186	
187	  // Redis transport (primary or fallback)
188	  if (transport === "redis" || (transport === "both" && !sent)) {
189	    if (cfg.redisUrl && cfg.redisToken) {
190	      const msg: RelayMessage = { from: cfg.botName, text, ts: new Date().toISOString() };
191	      const key = redisKey(targetBot);
192	      await redisCommand(["LPUSH", key, JSON.stringify(msg)]);
193	      sent = true;
194	        console.log(`[relay] ✓ sent via REDIS to key "${key}" (transport=${transport})`);
195	    }
196	  }
197	
198	  if (!sent) {
199	    console.error(`[relay] failed to send via any transport (transport=${transport})`);
200	    return;
201	  }
202	
203	  if (transport === "redis" || transport === "both") ensurePollerRunning();
204	
205	  const display = `📤 sent by ${cfg.botName} [${cfg.botName} -> ${targetBot}]\n${text}`;
206	  await bot.api.sendMessage(cfg.groupChatId, display).catch((err) =>
207	    console.error("[relay] group sendMessage failed:", err),
208	  );
209	}
